import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) throw new Error("Could not find root element");

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum RiskType {
  PII = 'PII',
  SECRET = 'SECRET',
  INTERNAL_ID = 'INTERNAL_ID',
  SENSITIVE_LOGIC = 'SENSITIVE_LOGIC'
}

export interface Finding {
  id: string;
  type: RiskType;
  originalText: string;
  suggestedReplacement: string;
  lineNumber: number;
  explanation: string;
  severity: 'low' | 'medium' | 'high';
}

export interface CodeFile {
  id: string;
  name: string;
  path: string;
  originalContent: string;
  cleanedContent?: string;
  status: 'pending' | 'analyzing' | 'cleaned' | 'error';
  findings: Finding[];
  lastActionAt?: number;
}

export interface MLReport {
  summary: {
    totalFindings: number;
    riskScore: number;
    breakdown: Record<RiskType, number>;
  };
  findings: Finding[];
}

import { GoogleGenAI, Type } from "@google/genai";
import { MLReport, RiskType } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const analyzeCodeLocally = async (filename: string, code: string): Promise<MLReport> => {
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Analyze the following code for security and privacy risks. 
      Identify:
      1. PII (Names, emails, phones)
      2. Secrets (API keys, passwords, tokens)
      3. Internal Identifiers (Internal hostnames, proprietary project names, specific employee IDs)
      4. Insecure Patterns.

      Return a JSON report.

      CODE:
      Filename: ${filename}
      ---
      ${code}`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          summary: {
            type: Type.OBJECT,
            properties: {
              totalFindings: { type: Type.NUMBER },
              riskScore: { type: Type.NUMBER },
              breakdown: {
                type: Type.OBJECT,
                properties: {
                  [RiskType.PII]: { type: Type.NUMBER },
                  [RiskType.SECRET]: { type: Type.NUMBER },
                  [RiskType.INTERNAL_ID]: { type: Type.NUMBER },
                  [RiskType.SENSITIVE_LOGIC]: { type: Type.NUMBER },
                },
                required: [RiskType.PII, RiskType.SECRET, RiskType.INTERNAL_ID, RiskType.SENSITIVE_LOGIC]
              }
            },
            required: ["totalFindings", "riskScore", "breakdown"]
          },
          findings: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                id: { type: Type.STRING },
                type: { type: Type.STRING, enum: Object.values(RiskType) },
                originalText: { type: Type.STRING },
                suggestedReplacement: { type: Type.STRING },
                lineNumber: { type: Type.NUMBER },
                explanation: { type: Type.STRING },
                severity: { type: Type.STRING, enum: ['low', 'medium', 'high'] }
              },
              required: ["id", "type", "originalText", "suggestedReplacement", "lineNumber", "explanation", "severity"]
            }
          }
        },
        required: ["summary", "findings"]
      }
    }
  });

  try {
    return JSON.parse(response.text || '{}') as MLReport;
  } catch (e) {
    console.error("Failed to parse ML response", e);
    throw new Error("Local ML Engine failed to produce a structured report.");
  }
};

