import React, { useState, useEffect, useCallback } from 'react';
import Sidebar from './components/Sidebar';
import FilePanel from './components/FilePanel';
import CodeViewer from './components/CodeViewer';
import { CodeFile, MLReport } from './types';
import { analyzeCodeLocally } from './services/geminiService';
import { Layout, Search, AlertCircle, Info } from 'lucide-react';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [files, setFiles] = useState<CodeFile[]>([]);
  const [selectedFileId, setSelectedFileId] = useState<string | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (!e.target.files) return;

    const newFiles: CodeFile[] = Array.from(e.target.files).map(file => ({
      id: Math.random().toString(36).substr(2, 9),
      name: file.name,
      path: `C:\\Projects\\Internal\\${file.name}`,
      originalContent: '', // Placeholder, will read content
      status: 'pending',
      findings: []
    }));

    // For demo purposes, we'll populate some mock contents if it's empty
    // In a real app, you'd use FileReader
    newFiles.forEach(nf => {
      const reader = new FileReader();
      const actualFile = Array.from(e.target.files!).find(f => f.name === nf.name);
      if (actualFile) {
        reader.onload = (event) => {
          setFiles(prev => prev.map(p => p.id === nf.id ? { ...p, originalContent: event.target?.result as string } : p));
        };
        reader.readAsText(actualFile);
      }
    });

    setFiles(prev => [...prev, ...newFiles]);
    if (!selectedFileId && newFiles.length > 0) setSelectedFileId(newFiles[0].id);
  };

  const handleCleanCode = async (id: string) => {
    const file = files.find(f => f.id === id);
    if (!file) return;

    setFiles(prev => prev.map(f => f.id === id ? { ...f, status: 'analyzing' } : f));
    setIsProcessing(true);

    try {
      const report: MLReport = await analyzeCodeLocally(file.name, file.originalContent);

      // Perform local "Rewrite" simulation
      let cleaned = file.originalContent;
      // Sort findings by position (descending) to avoid offset issues
      const sortedFindings = [...report.findings].sort((a, b) => b.lineNumber - a.lineNumber);

      // Simple line-based replacement for demo
      const lines = cleaned.split('\n');
      report.findings.forEach(f => {
        const lineIdx = f.lineNumber - 1;
        if (lines[lineIdx]) {
          lines[lineIdx] = lines[lineIdx].replace(f.originalText, f.suggestedReplacement);
        }
      });
      cleaned = lines.join('\n');

      setFiles(prev => prev.map(f => f.id === id ? {
        ...f,
        status: 'cleaned',
        findings: report.findings,
        cleanedContent: cleaned,
        lastActionAt: Date.now()
      } : f));
    } catch (error) {
      console.error(error);
      setFiles(prev => prev.map(f => f.id === id ? { ...f, status: 'error' } : f));
    } finally {
      setIsProcessing(false);
    }
  };

  const handleUndo = (id: string) => {
    setFiles(prev => prev.map(f => f.id === id ? {
      ...f,
      status: 'pending',
      cleanedContent: undefined,
      findings: []
    } : f));
  };

  const selectedFile = files.find(f => f.id === selectedFileId);

  return (
    <div className="flex h-screen bg-[#0f172a] text-slate-200 selection:bg-indigo-500/30">
      <Sidebar activeTab={activeTab} setActiveTab={setActiveTab} />

      <main className="flex-1 flex flex-col min-w-0">
        {/* Header Section */}
        <header className="h-16 border-b border-slate-800 flex items-center justify-between px-6 bg-slate-900/40 shrink-0">
          <div className="flex items-center gap-4">
            <div className="flex items-center gap-2 bg-slate-800/50 rounded-full px-3 py-1.5 text-xs text-slate-400">
              <Search className="w-3.5 h-3.5" />
              <span>C:\Users\Developer\AppData\Local\CodeCleaner\Models\bert-v4.bin</span>
            </div>
          </div>
          <div className="flex items-center gap-4">
             <div className="flex items-center gap-2 text-xs text-emerald-500 bg-emerald-500/10 px-3 py-1.5 rounded-full border border-emerald-500/20">
                <div className="w-2 h-2 bg-emerald-500 rounded-full animate-pulse" />
                <span>Engine Active</span>
             </div>
          </div>
        </header>

        {activeTab === 'dashboard' ? (
          <div className="flex-1 flex overflow-hidden">
            <FilePanel 
              files={files} 
              selectedFileId={selectedFileId} 
              onSelectFile={setSelectedFileId} 
              onFileUpload={handleFileUpload}
            />

            {selectedFile ? (
              <CodeViewer 
                file={selectedFile} 
                onClean={handleCleanCode} 
                onUndo={handleUndo} 
              />
            ) : (
              <div className="flex-1 flex flex-col items-center justify-center p-12 text-center text-slate-500 space-y-6">
                <div className="bg-slate-800/30 p-8 rounded-full">
                  <Layout className="w-24 h-24 opacity-10" />
                </div>
                <div className="max-w-md">
                  <h3 className="text-xl font-bold text-slate-300 mb-2">Ready to Secure Your Code</h3>
                  <p className="text-sm">Import your source files or directory to start the local privacy scrub process. No data leaves this device.</p>
                </div>
                <label className="cursor-pointer bg-indigo-600 hover:bg-indigo-500 text-white font-semibold px-8 py-3 rounded-xl transition-all shadow-xl shadow-indigo-600/20">
                  Select Files
                  <input type="file" multiple className="hidden" onChange={handleFileUpload} />
                </label>
              </div>
            )}
          </div>
        ) : activeTab === 'audit' ? (
          <div className="p-12 max-w-5xl mx-auto w-full">
             <h2 className="text-2xl font-bold mb-8 flex items-center gap-3">
               <Info className="text-indigo-400" /> Audit Log & Version History
             </h2>
             <div className="space-y-4">
                {files.filter(f => f.status === 'cleaned').map(file => (
                  <div key={file.id} className="bg-slate-800/40 p-6 rounded-xl border border-slate-700 flex items-center justify-between">
                    <div>
                      <h4 className="font-semibold text-slate-200">{file.name}</h4>
                      <p className="text-xs text-slate-500 mt-1">Status: Sanitized and ready for AI Assist</p>
                      <div className="flex gap-2 mt-3">
                        {Object.values(file.findings).reduce((acc: any, curr) => {
                          acc[curr.type] = (acc[curr.type] || 0) + 1;
                          return acc;
                        }, {} as any) && (
                           <div className="flex gap-2">
                             {Array.from(new Set(file.findings.map(f => f.type))).map(type => (
                               <span key={type} className="text-[10px] bg-indigo-500/10 text-indigo-400 border border-indigo-500/20 px-2 py-0.5 rounded-full uppercase font-bold">
                                 {type}
                               </span>
                             ))}
                           </div>
                        )}
                      </div>
                    </div>
                    <div className="text-right">
                      <span className="text-[10px] text-slate-500 block mb-2">
                        {file.lastActionAt ? new Date(file.lastActionAt).toLocaleString() : ''}
                      </span>
                      <button 
                        onClick={() => handleUndo(file.id)}
                        className="text-xs font-semibold text-rose-400 hover:text-rose-300 transition-colors"
                      >
                        Rollback Changes
                      </button>
                    </div>
                  </div>
                ))}
                {files.filter(f => f.status === 'cleaned').length === 0 && (
                   <div className="text-center py-24 bg-slate-900/50 rounded-2xl border-2 border-dashed border-slate-800">
                      <p className="text-slate-500 italic">No processed files yet. Start cleaning in the Workspace.</p>
                   </div>
                )}
             </div>
          </div>
        ) : (
          <div className="p-12 max-w-2xl mx-auto w-full space-y-12">
            <div>
              <h2 className="text-2xl font-bold mb-2">Model Configuration</h2>
              <p className="text-slate-400 text-sm">Fine-tune the local analysis parameters.</p>
            </div>

            <div className="space-y-6">
              <div className="space-y-2">
                <label className="text-xs font-bold text-slate-500 uppercase">Detection Sensitivity</label>
                <input type="range" className="w-full accent-indigo-500" />
                <div className="flex justify-between text-[10px] text-slate-600">
                  <span>Relaxed</span>
                  <span>Strict (Recommended)</span>
                  <span>Paranoid</span>
                </div>
              </div>

              <div className="p-4 bg-amber-500/5 border border-amber-500/20 rounded-lg flex gap-4">
                <AlertCircle className="w-5 h-5 text-amber-500 shrink-0" />
                <div className="text-xs text-amber-400/80 leading-relaxed">
                  <strong>Deep Learning Engine:</strong> These settings only affect the local execution environment. Changes here may increase CPU/GPU usage during analysis.
                </div>
              </div>
            </div>
          </div>
        )}
      </main>

      {/* Global Status Footer */}
      <footer className="h-8 border-t border-slate-800 bg-slate-900/80 fixed bottom-0 left-0 right-0 z-50 px-4 flex items-center justify-between text-[10px] text-slate-500 font-medium">
        <div className="flex gap-4">
           <span>CodeCleaner Pro v1.0.4-stable</span>
           <span>|</span>
           <span className="flex items-center gap-1">
             <div className="w-1.5 h-1.5 bg-indigo-500 rounded-full" />
             Pipeline Ready
           </span>
        </div>
        <div className="flex gap-4">
           <span>Files: {files.length}</span>
           <span>Cleaned: {files.filter(f => f.status === 'cleaned').length}</span>
           <span className="text-emerald-500">Encryption: AES-256 (Local Vault)</span>
        </div>
      </footer>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useCallback } from 'react';
import Sidebar from './components/Sidebar';
import FilePanel from './components/FilePanel';
import CodeViewer from './components/CodeViewer';
import { CodeFile, MLReport, Finding } from './types';
import { analyzeCodeLocally } from './services/geminiService';
import { Layout, Search, AlertCircle, Info } from 'lucide-react';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [files, setFiles] = useState<CodeFile[]>([]);
  const [selectedFileId, setSelectedFileId] = useState<string | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (!e.target.files) return;

    // Fix: Explicitly cast the FileList to a File array to ensure proper typing during mapping
    const filesArray = Array.from(e.target.files) as File[];

    const newFiles: CodeFile[] = filesArray.map(file => ({
      id: Math.random().toString(36).substr(2, 9),
      name: file.name,
      path: `C:\\Projects\\Internal\\${file.name}`,
      originalContent: '', // Placeholder, will read content
      status: 'pending',
      findings: []
    }));

    // For demo purposes, we'll populate some mock contents if it's empty
    // In a real app, you'd use FileReader
    newFiles.forEach(nf => {
      const reader = new FileReader();
      // Fix: Use the correctly typed filesArray to find the specific File object
      const actualFile = filesArray.find(f => f.name === nf.name);
      if (actualFile) {
        reader.onload = (event) => {
          setFiles(prev => prev.map(p => p.id === nf.id ? { ...p, originalContent: event.target?.result as string } : p));
        };
        // Fix: passing actualFile (typed as File, which extends Blob) to readAsText
        reader.readAsText(actualFile);
      }
    });

    setFiles(prev => [...prev, ...newFiles]);
    if (!selectedFileId && newFiles.length > 0) setSelectedFileId(newFiles[0].id);
  };

  const handleCleanCode = async (id: string) => {
    const file = files.find(f => f.id === id);
    if (!file) return;

    setFiles(prev => prev.map(f => f.id === id ? { ...f, status: 'analyzing' } : f));
    setIsProcessing(true);

    try {
      const report: MLReport = await analyzeCodeLocally(file.name, file.originalContent);

      // Perform local "Rewrite" simulation
      let cleaned = file.originalContent;
      // Sort findings by position (descending) to avoid offset issues
      const sortedFindings = [...report.findings].sort((a, b) => b.lineNumber - a.lineNumber);

      // Simple line-based replacement for demo
      const lines = cleaned.split('\n');
      report.findings.forEach(f => {
        const lineIdx = f.lineNumber - 1;
        if (lines[lineIdx]) {
          lines[lineIdx] = lines[lineIdx].replace(f.originalText, f.suggestedReplacement);
        }
      });
      cleaned = lines.join('\n');

      setFiles(prev => prev.map(f => f.id === id ? {
        ...f,
        status: 'cleaned',
        findings: report.findings,
        cleanedContent: cleaned,
        lastActionAt: Date.now()
      } : f));
    } catch (error) {
      console.error(error);
      setFiles(prev => prev.map(f => f.id === id ? { ...f, status: 'error' } : f));
    } finally {
      setIsProcessing(false);
    }
  };

  const handleUndo = (id: string) => {
    setFiles(prev => prev.map(f => f.id === id ? {
      ...f,
      status: 'pending',
      cleanedContent: undefined,
      findings: []
    } : f));
  };

  const selectedFile = files.find(f => f.id === selectedFileId);

  return (
    <div className="flex h-screen bg-[#0f172a] text-slate-200 selection:bg-indigo-500/30">
      <Sidebar activeTab={activeTab} setActiveTab={setActiveTab} />

      <main className="flex-1 flex flex-col min-w-0">
        {/* Header Section */}
        <header className="h-16 border-b border-slate-800 flex items-center justify-between px-6 bg-slate-900/40 shrink-0">
          <div className="flex items-center gap-4">
            <div className="flex items-center gap-2 bg-slate-800/50 rounded-full px-3 py-1.5 text-xs text-slate-400">
              <Search className="w-3.5 h-3.5" />
              <span>C:\Users\Developer\AppData\Local\CodeCleaner\Models\bert-v4.bin</span>
            </div>
          </div>
          <div className="flex items-center gap-4">
             <div className="flex items-center gap-2 text-xs text-emerald-500 bg-emerald-500/10 px-3 py-1.5 rounded-full border border-emerald-500/20">
                <div className="w-2 h-2 bg-emerald-500 rounded-full animate-pulse" />
                <span>Engine Active</span>
             </div>
          </div>
        </header>

        {activeTab === 'dashboard' ? (
          <div className="flex-1 flex overflow-hidden">
            <FilePanel 
              files={files} 
              selectedFileId={selectedFileId} 
              onSelectFile={setSelectedFileId} 
              onFileUpload={handleFileUpload}
            />

            {selectedFile ? (
              <CodeViewer 
                file={selectedFile} 
                onClean={handleCleanCode} 
                onUndo={handleUndo} 
              />
            ) : (
              <div className="flex-1 flex flex-col items-center justify-center p-12 text-center text-slate-500 space-y-6">
                <div className="bg-slate-800/30 p-8 rounded-full">
                  <Layout className="w-24 h-24 opacity-10" />
                </div>
                <div className="max-w-md">
                  <h3 className="text-xl font-bold text-slate-300 mb-2">Ready to Secure Your Code</h3>
                  <p className="text-sm">Import your source files or directory to start the local privacy scrub process. No data leaves this device.</p>
                </div>
                <label className="cursor-pointer bg-indigo-600 hover:bg-indigo-500 text-white font-semibold px-8 py-3 rounded-xl transition-all shadow-xl shadow-indigo-600/20">
                  Select Files
                  <input type="file" multiple className="hidden" onChange={handleFileUpload} />
                </label>
              </div>
            )}
          </div>
        ) : activeTab === 'audit' ? (
          <div className="p-12 max-w-5xl mx-auto w-full">
             <h2 className="text-2xl font-bold mb-8 flex items-center gap-3">
               <Info className="text-indigo-400" /> Audit Log & Version History
             </h2>
             <div className="space-y-4">
                {files.filter(f => f.status === 'cleaned').map(file => (
                  <div key={file.id} className="bg-slate-800/40 p-6 rounded-xl border border-slate-700 flex items-center justify-between">
                    <div>
                      <h4 className="font-semibold text-slate-200">{file.name}</h4>
                      <p className="text-xs text-slate-500 mt-1">Status: Sanitized and ready for AI Assist</p>
                      <div className="flex gap-2 mt-3">
                        {/* Fix: Directly use file.findings array and provide explicit types for reduce function parameters to fix 'unknown' property access errors */}
                        {file.findings.reduce((acc: Record<string, number>, curr: Finding) => {
                          acc[curr.type] = (acc[curr.type] || 0) + 1;
                          return acc;
                        }, {} as Record<string, number>) && (
                           <div className="flex gap-2">
                             {Array.from(new Set(file.findings.map(f => f.type))).map(type => (
                               <span key={type} className="text-[10px] bg-indigo-500/10 text-indigo-400 border border-indigo-500/20 px-2 py-0.5 rounded-full uppercase font-bold">
                                 {type}
                               </span>
                             ))}
                           </div>
                        )}
                      </div>
                    </div>
                    <div className="text-right">
                      <span className="text-[10px] text-slate-500 block mb-2">
                        {file.lastActionAt ? new Date(file.lastActionAt).toLocaleString() : ''}
                      </span>
                      <button 
                        onClick={() => handleUndo(file.id)}
                        className="text-xs font-semibold text-rose-400 hover:text-rose-300 transition-colors"
                      >
                        Rollback Changes
                      </button>
                    </div>
                  </div>
                ))}
                {files.filter(f => f.status === 'cleaned').length === 0 && (
                   <div className="text-center py-24 bg-slate-900/50 rounded-2xl border-2 border-dashed border-slate-800">
                      <p className="text-slate-500 italic">No processed files yet. Start cleaning in the Workspace.</p>
                   </div>
                )}
             </div>
          </div>
        ) : (
          <div className="p-12 max-w-2xl mx-auto w-full space-y-12">
            <div>
              <h2 className="text-2xl font-bold mb-2">Model Configuration</h2>
              <p className="text-slate-400 text-sm">Fine-tune the local analysis parameters.</p>
            </div>

            <div className="space-y-6">
              <div className="space-y-2">
                <label className="text-xs font-bold text-slate-500 uppercase">Detection Sensitivity</label>
                <input type="range" className="w-full accent-indigo-500" />
                <div className="flex justify-between text-[10px] text-slate-600">
                  <span>Relaxed</span>
                  <span>Strict (Recommended)</span>
                  <span>Paranoid</span>
                </div>
              </div>

              <div className="p-4 bg-amber-500/5 border border-amber-500/20 rounded-lg flex gap-4">
                <AlertCircle className="w-5 h-5 text-amber-500 shrink-0" />
                <div className="text-xs text-amber-400/80 leading-relaxed">
                  <strong>Deep Learning Engine:</strong> These settings only affect the local execution environment. Changes here may increase CPU/GPU usage during analysis.
                </div>
              </div>
            </div>
          </div>
        )}
      </main>

      {/* Global Status Footer */}
      <footer className="h-8 border-t border-slate-800 bg-slate-900/80 fixed bottom-0 left-0 right-0 z-50 px-4 flex items-center justify-between text-[10px] text-slate-500 font-medium">
        <div className="flex gap-4">
           <span>CodeCleaner Pro v1.0.4-stable</span>
           <span>|</span>
           <span className="flex items-center gap-1">
             <div className="w-1.5 h-1.5 bg-indigo-500 rounded-full" />
             Pipeline Ready
           </span>
        </div>
        <div className="flex gap-4">
           <span>Files: {files.length}</span>
           <span>Cleaned: {files.filter(f => f.status === 'cleaned').length}</span>
           <span className="text-emerald-500">Encryption: AES-256 (Local Vault)</span>
        </div>
      </footer>
    </div>
  );
};

export default App;

export enum RiskType {
  PII = 'PII',
  SECRET = 'SECRET',
  INTERNAL_ID = 'INTERNAL_ID',
  SENSITIVE_LOGIC = 'SENSITIVE_LOGIC'
}

export interface Finding {
  id: string;
  type: RiskType;
  originalText: string;
  suggestedReplacement: string; // This will now act as the unique token like __REDACTED_001__
  lineNumber: number;
  explanation: string;
  severity: 'low' | 'medium' | 'high';
}

export interface CodeFile {
  id: string;
  name: string;
  path: string;
  originalContent: string;
  cleanedContent?: string;
  updatedContent?: string; // Content returned from external AI
  status: 'pending' | 'analyzing' | 'cleaned' | 'restored' | 'error';
  findings: Finding[];
  lastActionAt?: number;
  folderId: string;
}

export interface Folder {
  id: string;
  name: string;
  parentId: string | null;
  isOpen?: boolean;
}

export interface MLReport {
  summary: {
    totalFindings: number;
    riskScore: number;
    breakdown: Record<RiskType, number>;
  };
  findings: Finding[];
}

import React, { useState } from 'react';
import { Folder, FolderPlus, Trash2, Edit2, ChevronRight, ChevronDown, FileCode, Plus } from 'lucide-react';
import { Folder as FolderType, CodeFile } from '../types';

interface FolderAsideProps {
  folders: FolderType[];
  files: CodeFile[];
  selectedFileId: string | null;
  onSelectFile: (id: string) => void;
  onAddFolder: (parentId: string | null) => void;
  onDeleteFolder: (id: string) => void;
  onRenameFolder: (id: string, name: string) => void;
  onFileUpload: (event: React.ChangeEvent<HTMLInputElement>, folderId: string) => void;
}

const FolderAside: React.FC<FolderAsideProps> = ({ 
  folders, files, selectedFileId, onSelectFile, onAddFolder, onDeleteFolder, onRenameFolder, onFileUpload 
}) => {
  const [editingId, setEditingId] = useState<string | null>(null);

  const renderFolder = (parentId: string | null, depth = 0) => {
    return folders
      .filter(f => f.parentId === parentId)
      .map(folder => (
        <div key={folder.id} className="select-none">
          <div 
            className="group flex items-center gap-2 px-3 py-1.5 hover:bg-slate-800 rounded-md cursor-pointer transition-colors"
            style={{ paddingLeft: `${depth * 12 + 12}px` }}
          >
            <ChevronDown className="w-3.5 h-3.5 text-slate-500" />
            <Folder className="w-4 h-4 text-indigo-400" />
            {editingId === folder.id ? (
              <input
                autoFocus
                className="bg-slate-900 text-xs text-slate-200 border border-indigo-500 rounded px-1 outline-none w-24"
                defaultValue={folder.name}
                onBlur={(e) => {
                  onRenameFolder(folder.id, e.target.value);
                  setEditingId(null);
                }}
                onKeyDown={(e) => e.key === 'Enter' && setEditingId(null)}
              />
            ) : (
              <span className="text-xs font-medium text-slate-300 truncate flex-1">{folder.name}</span>
            )}

            <div className="hidden group-hover:flex items-center gap-1">
              <button onClick={() => setEditingId(folder.id)} className="p-1 hover:text-indigo-400"><Edit2 className="w-3 h-3" /></button>
              <button onClick={() => onAddFolder(folder.id)} className="p-1 hover:text-indigo-400"><Plus className="w-3 h-3" /></button>
              {folder.parentId !== null && (
                <button onClick={() => onDeleteFolder(folder.id)} className="p-1 hover:text-rose-400"><Trash2 className="w-3 h-3" /></button>
              )}
            </div>
          </div>

          <div className="mt-0.5">
            {/* Render files in this folder */}
            {files.filter(f => f.folderId === folder.id).map(file => (
              <div 
                key={file.id}
                onClick={() => onSelectFile(file.id)}
                className={`flex items-center gap-2 px-3 py-1.5 cursor-pointer rounded-md text-[11px] transition-colors ${
                  selectedFileId === file.id ? 'bg-indigo-600/20 text-indigo-300 font-semibold' : 'text-slate-500 hover:bg-slate-800 hover:text-slate-300'
                }`}
                style={{ paddingLeft: `${(depth + 1) * 12 + 16}px` }}
              >
                <FileCode className="w-3.5 h-3.5" />
                <span className="truncate">{file.name}</span>
              </div>
            ))}
            {/* Render subfolders */}
            {renderFolder(folder.id, depth + 1)}
          </div>
        </div>
      ));
  };

  return (
    <div className="w-64 border-r border-slate-800 bg-slate-900/40 flex flex-col shrink-0">
      <div className="p-4 border-b border-slate-800 flex justify-between items-center bg-slate-900/60">
        <h2 className="text-[10px] font-bold text-slate-500 uppercase tracking-widest">Explorer</h2>
        <button 
          onClick={() => onAddFolder(null)}
          className="p-1.5 hover:bg-slate-800 rounded text-slate-400"
        >
          <FolderPlus className="w-4 h-4" />
        </button>
      </div>
      <div className="flex-1 overflow-y-auto py-4 px-2 custom-scrollbar">
        {renderFolder(null)}
      </div>
    </div>
  );
};

export default FolderAside;

import React, { useState } from 'react';
import { X, Upload, FileCode, CheckCircle2, AlertCircle } from 'lucide-react';
import { CodeFile } from '../types';

interface RestoreModalProps {
  isOpen: boolean;
  onClose: () => void;
  onRestore: (fileId: string, modifiedContent: string) => void;
  availableFiles: CodeFile[];
}

const RestoreModal: React.FC<RestoreModalProps> = ({ isOpen, onClose, onRestore, availableFiles }) => {
  const [selectedFileId, setSelectedFileId] = useState<string>('');
  const [modifiedContent, setModifiedContent] = useState<string>('');
  const [importedFileName, setImportedFileName] = useState<string>('');

  if (!isOpen) return null;

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (event) => {
        setModifiedContent(event.target?.result as string);
        setImportedFileName(file.name);
      };
      reader.readAsText(file);
    }
  };

  const canSubmit = selectedFileId && modifiedContent;

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center bg-black/60 backdrop-blur-sm p-4">
      <div className="bg-slate-900 border border-slate-800 w-full max-w-lg rounded-2xl shadow-2xl flex flex-col overflow-hidden">
        <div className="p-6 border-b border-slate-800 flex justify-between items-center">
          <h2 className="text-xl font-bold flex items-center gap-2">
            <CheckCircle2 className="w-5 h-5 text-emerald-500" />
            Restore Script
          </h2>
          <button onClick={onClose} className="p-2 hover:bg-slate-800 rounded-full transition-colors">
            <X className="w-5 h-5" />
          </button>
        </div>

        <div className="p-8 space-y-6">
          <p className="text-sm text-slate-400 leading-relaxed">
            Re-inject original private data into a script that has been modified externally by AI services.
          </p>

          <div className="space-y-4">
            <div className="space-y-2">
              <label className="text-xs font-bold text-slate-500 uppercase tracking-wider">1. Select Original Reference</label>
              <select 
                className="w-full bg-slate-800 border border-slate-700 rounded-xl px-4 py-3 text-sm text-slate-200 outline-none focus:border-indigo-500 transition-colors"
                value={selectedFileId}
                onChange={(e) => setSelectedFileId(e.target.value)}
              >
                <option value="">Select a file to match metadata...</option>
                {availableFiles.map(f => (
                  <option key={f.id} value={f.id}>{f.name} ({f.findings.length} markers)</option>
                ))}
              </select>
            </div>

            <div className="space-y-2">
              <label className="text-xs font-bold text-slate-500 uppercase tracking-wider">2. Import Modified File</label>
              <label className={`block border-2 border-dashed rounded-xl p-8 text-center cursor-pointer transition-all ${
                modifiedContent ? 'border-emerald-500/50 bg-emerald-500/5' : 'border-slate-700 hover:border-slate-600 bg-slate-800/20'
              }`}>
                <input type="file" className="hidden" onChange={handleFileUpload} />
                <div className="flex flex-col items-center gap-2">
                  <Upload className={`w-8 h-8 ${modifiedContent ? 'text-emerald-500' : 'text-slate-500'}`} />
                  <span className="text-sm font-medium">
                    {importedFileName || 'Click to upload AI-modified file'}
                  </span>
                  {modifiedContent && <span className="text-[10px] text-emerald-500 font-bold">FILE CAPTURED</span>}
                </div>
              </label>
            </div>
          </div>
        </div>

        <div className="p-6 bg-slate-900/80 border-t border-slate-800 flex justify-end gap-3">
          <button 
            onClick={onClose}
            className="px-6 py-2.5 rounded-xl text-sm font-semibold text-slate-400 hover:bg-slate-800 transition-colors"
          >
            Cancel
          </button>
          <button 
            disabled={!canSubmit}
            onClick={() => onRestore(selectedFileId, modifiedContent)}
            className="px-8 py-2.5 rounded-xl text-sm font-bold bg-indigo-600 hover:bg-indigo-500 disabled:opacity-30 disabled:cursor-not-allowed text-white transition-all shadow-lg shadow-indigo-600/20"
          >
            Restore & Save
          </button>
        </div>
      </div>
    </div>
  );
};

export default RestoreModal;

import React, { useState, useEffect, useCallback } from 'react';
import Sidebar from './components/Sidebar';
import FolderAside from './components/FolderAside';
import RestoreModal from './components/RestoreModal';
import { CodeFile, MLReport, Finding, Folder, RiskType } from './types';
import { analyzeCodeLocally } from './services/geminiService';
import { Layout, Search, AlertCircle, Info, Zap, RotateCcw, ShieldAlert, Check, RefreshCw, Upload, FileText } from 'lucide-react';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [files, setFiles] = useState<CodeFile[]>([]);
  const [folders, setFolders] = useState<Folder[]>([
    { id: 'input', name: 'input', parentId: null },
    { id: 'cleaned', name: 'cleaned', parentId: null },
    { id: 'updated', name: 'updated', parentId: null },
  ]);
  const [selectedFileId, setSelectedFileId] = useState<string | null>(null);
  const [isRestoreModalOpen, setIsRestoreModalOpen] = useState(false);
  const [isProcessing, setIsProcessing] = useState(false);

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>, folderId: string = 'input') => {
    if (!e.target.files) return;
    const filesArray = Array.from(e.target.files) as File[];

    const newFiles: CodeFile[] = filesArray.map(file => ({
      id: Math.random().toString(36).substr(2, 9),
      name: file.name,
      path: `C:\\Projects\\Local\\${file.name}`,
      originalContent: '',
      status: 'pending',
      findings: [],
      folderId: folderId
    }));

    newFiles.forEach(nf => {
      const reader = new FileReader();
      const actualFile = filesArray.find(f => f.name === nf.name);
      if (actualFile) {
        reader.onload = (event) => {
          setFiles(prev => prev.map(p => p.id === nf.id ? { ...p, originalContent: event.target?.result as string } : p));
        };
        reader.readAsText(actualFile);
      }
    });

    setFiles(prev => [...prev, ...newFiles]);
    if (!selectedFileId && newFiles.length > 0) setSelectedFileId(newFiles[0].id);
  };

  const handleCleanCode = async (id: string) => {
    const file = files.find(f => f.id === id);
    if (!file) return;

    setFiles(prev => prev.map(f => f.id === id ? { ...f, status: 'analyzing' } : f));
    setIsProcessing(true);

    try {
      const report: MLReport = await analyzeCodeLocally(file.name, file.originalContent);

      // Use Unique Tokens for cleaning
      let cleaned = file.originalContent;
      const findingsWithTokens: Finding[] = report.findings.map((f, index) => ({
        ...f,
        id: `f-${index}`,
        suggestedReplacement: `__REDACTED_${f.type}_${String(index + 1).padStart(3, '0')}__`
      }));

      // Sort findings by position (descending) to avoid offset issues
      const sortedFindings = [...findingsWithTokens].sort((a, b) => b.lineNumber - a.lineNumber);
      const lines = cleaned.split('\n');

      sortedFindings.forEach(f => {
        const lineIdx = f.lineNumber - 1;
        if (lines[lineIdx]) {
          lines[lineIdx] = lines[lineIdx].replace(f.originalText, f.suggestedReplacement);
        }
      });
      cleaned = lines.join('\n');

      setFiles(prev => prev.map(f => f.id === id ? {
        ...f,
        status: 'cleaned',
        findings: findingsWithTokens,
        cleanedContent: cleaned,
        lastActionAt: Date.now(),
        folderId: 'cleaned' // Move to cleaned folder
      } : f));
    } catch (error) {
      console.error(error);
      setFiles(prev => prev.map(f => f.id === id ? { ...f, status: 'error' } : f));
    } finally {
      setIsProcessing(false);
    }
  };

  const handleRestoreScript = (fileId: string, modifiedContent: string) => {
    const originalFile = files.find(f => f.id === fileId);
    if (!originalFile) return;

    // Logic to swap tokens back to original data
    let restored = modifiedContent;
    originalFile.findings.forEach(finding => {
      // Global search for the token in the modified content
      const token = finding.suggestedReplacement;
      const originalValue = finding.originalText;
      restored = restored.split(token).join(originalValue);
    });

    const restoredFileId = Math.random().toString(36).substr(2, 9);
    const restoredFile: CodeFile = {
      id: restoredFileId,
      name: `Restored_${originalFile.name}`,
      path: `C:\\Projects\\Updated\\${originalFile.name}`,
      originalContent: originalFile.originalContent,
      updatedContent: modifiedContent, // store the modified state too
      cleanedContent: restored,
      status: 'restored',
      findings: [],
      folderId: 'updated'
    };

    setFiles(prev => [...prev, restoredFile]);
    setSelectedFileId(restoredFileId);
    setIsRestoreModalOpen(false);
  };

  const handleUndo = (id: string) => {
