      console.error(error);
      setFiles(prev => prev.map(f => f.id === id ? { ...f, status: 'error' } : f));
    } finally {
      setIsProcessing(false);
    }
  };

  const handleRestoreScript = (fileId: string, modifiedContent: string) => {
    const originalFile = files.find(f => f.id === fileId);
    if (!originalFile) return;

    // Logic to swap tokens back to original data
    let restored = modifiedContent;
    originalFile.findings.forEach(finding => {
      const token = finding.suggestedReplacement;
      const originalValue = finding.originalText;
      restored = restored.split(token).join(originalValue);
    });

    const restoredFileId = Math.random().toString(36).substr(2, 9);
    const restoredFile: CodeFile = {
      id: restoredFileId,
      name: `Restored_${originalFile.name.replace(/_cleaned_\d{2}-\d{2}-\d{4}/, '')}`,
      path: `C:\\Projects\\Updated\\${originalFile.name}`,
      originalContent: originalFile.originalContent,
      updatedContent: modifiedContent,
      cleanedContent: restored,
      status: 'restored',
      findings: [],
      folderId: 'updated'
    };

    setFiles(prev => [...prev, restoredFile]);
    setSelectedFileId(restoredFileId);
    setIsRestoreModalOpen(false);
  };

  const handleUndo = (id: string) => {
    const file = files.find(f => f.id === id);
    if (!file) return;

    // If it's a cleaned file, we just delete it and select original if possible
    setFiles(prev => prev.filter(f => f.id !== id));
    setSelectedFileId(null);
  };

  const handleAddFolder = (parentId: string | null) => {
    const newFolder: Folder = {
      id: Math.random().toString(36).substr(2, 9),
      name: 'New Folder',
      parentId: parentId
    };
    setFolders([...folders, newFolder]);
  };

  const handleRenameFolder = (id: string, name: string) => {
    setFolders(folders.map(f => f.id === id ? { ...f, name } : f));
  };

  const handleDeleteFolder = (id: string) => {
    if (['input', 'cleaned', 'updated'].includes(id)) return; 
    setFolders(folders.filter(f => f.id !== id));
    setFiles(files.map(f => f.folderId === id ? { ...f, folderId: 'input' } : f));
  };

  const selectedFile = files.find(f => f.id === selectedFileId);

  return (
    <div className="flex h-screen bg-[#0f172a] text-slate-200 selection:bg-indigo-500/30 font-sans">
      <Sidebar activeTab={activeTab} setActiveTab={setActiveTab} />

      {activeTab === 'dashboard' && (
        <FolderAside 
          folders={folders} 
          files={files} 
          selectedFileId={selectedFileId} 
          onSelectFile={setSelectedFileId}
          onAddFolder={handleAddFolder}
          onDeleteFolder={handleDeleteFolder}
          onRenameFolder={handleRenameFolder}
          onFileUpload={handleFileUpload}
        />
      )}

      <main className="flex-1 flex flex-col min-w-0 bg-slate-950/20">
        <header className="h-14 border-b border-slate-800/60 flex items-center justify-between px-6 bg-slate-900/40 shrink-0 backdrop-blur-md">
          <div className="flex items-center gap-4">
            <span className="text-xs font-bold text-slate-400 flex items-center gap-2">
              <RefreshCw className={`w-3 h-3 ${isProcessing ? 'animate-spin text-indigo-400' : ''}`} />
              {isProcessing ? 'Processing Metadata...' : 'System Ready'}
            </span>
          </div>
          <div className="flex items-center gap-6">
             <div className="text-[10px] text-slate-500 font-mono flex items-center gap-2 bg-slate-800/30 px-3 py-1 rounded-full">
               <ShieldAlert className="w-3 h-3 text-amber-500" />
               SECURE LOCAL ENCLAVE v1.0
             </div>
          </div>
        </header>

        {activeTab === 'dashboard' ? (
          <div className="flex-1 flex flex-col overflow-hidden">
            {/* Code Preview Box */}
            <div className="flex-1 p-6 flex flex-col min-h-0">
               <div className="bg-slate-900 border border-slate-800 rounded-xl overflow-hidden flex flex-col shadow-2xl flex-1">
                  <div className="bg-slate-800/50 px-4 py-2 border-b border-slate-800 flex justify-between items-center">
                    <div className="flex items-center gap-3">
                      <FileText className="w-4 h-4 text-indigo-400" />
                      <span className="text-xs font-semibold text-slate-300">
                        {selectedFile ? selectedFile.name : 'No file selected'}
                      </span>
                    </div>
                    {selectedFile?.status === 'cleaned' && (
                      <span className="text-[10px] bg-emerald-500/10 text-emerald-400 px-2 py-0.5 rounded border border-emerald-500/20 font-bold">
                        CLEANED & TOKENIZED
                      </span>
                    )}
                  </div>
                  <div className="flex-1 bg-[#0d1117] p-6 code-font text-sm leading-relaxed overflow-auto whitespace-pre custom-scrollbar text-slate-300">
                    {selectedFile ? (
                      selectedFile.status === 'cleaned' || selectedFile.status === 'restored' 
                      ? (selectedFile.cleanedContent || selectedFile.originalContent)
                      : selectedFile.originalContent
                    ) : (
                      <div className="h-full flex flex-col items-center justify-center text-slate-600 gap-4">
                        <Layout className="w-16 h-16 opacity-5" />
                        <p className="text-sm italic">Select a file from the explorer to preview</p>
                      </div>
                    )}
                  </div>
               </div>
            </div>

            {/* Bottom Controls */}
            <div className="p-6 pt-0 border-t border-slate-800/40 bg-slate-900/20">
               <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                  {/* Action Group */}
