                        className="flex-1 flex items-center justify-center gap-2 bg-indigo-600 hover:bg-indigo-500 disabled:opacity-30 disabled:cursor-not-allowed text-white py-3 rounded-xl font-bold transition-all shadow-lg shadow-indigo-600/10"
                      >
                        <Zap className="w-4 h-4" />
                        Clean Code
                      </button>
                      <button 
                        onClick={() => setIsRestoreModalOpen(true)}
                        className="flex-1 flex items-center justify-center gap-2 bg-emerald-600 hover:bg-emerald-500 text-white py-3 rounded-xl font-bold transition-all shadow-lg shadow-emerald-600/10"
                      >
                        <RotateCcw className="w-4 h-4" />
                        Restore Script
                      </button>
                    </div>
