import AboutModal from './components/AboutModal';
import HelpPortal from './components/HelpPortal';
import CodeVault from './components/CodeVault';
import { CodeFile, MLReport, Finding, Folder, RiskType, TokenMapping } from './types';
import { analyzeCodeLocally } from './services/geminiService';
import { Layout, Search, AlertCircle, Info, Zap, RotateCcw, ShieldAlert, Check, RefreshCw, Upload, FileText } from 'lucide-react';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [files, setFiles] = useState<CodeFile[]>([]);
  const [folders, setFolders] = useState<Folder[]>([
    { id: 'input', name: 'input', parentId: null },
    { id: 'cleaned', name: 'cleaned', parentId: null },
    { id: 'updated', name: 'updated', parentId: null },
  ]);
  const [selectedFileId, setSelectedFileId] = useState<string | null>(null);
  const [isRestoreModalOpen, setIsRestoreModalOpen] = useState(false);
  const [isAboutModalOpen, setIsAboutModalOpen] = useState(false);
  const [isHelpPortalOpen, setIsHelpPortalOpen] = useState(false);
  const [isVaultOpen, setIsVaultOpen] = useState(false);
  const [isProcessing, setIsProcessing] = useState(false);

  // Persistent Token Mappings (The Registry)
  const [tokenRegistry, setTokenRegistry] = useState<TokenMapping[]>([]);

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>, folderId: string = 'input') => {
    if (!e.target.files) return;
    const filesArray = Array.from(e.target.files) as File[];

    const newFiles: CodeFile[] = filesArray.map(file => ({
      id: Math.random().toString(36).substr(2, 9),
      name: file.name,
      path: `C:\\Projects\\Local\\${file.name}`,
      originalContent: '',
      status: 'pending' as const,
      findings: [],
      folderId: folderId
    }));

    newFiles.forEach(nf => {
      const reader = new FileReader();
      const actualFile = filesArray.find(f => f.name === nf.name);
      if (actualFile) {
        reader.onload = (event) => {
          setFiles(prev => prev.map(p => p.id === nf.id ? { ...p, originalContent: event.target?.result as string } : p));
        };
        reader.readAsText(actualFile);
      }
    });

    setFiles(prev => [...prev, ...newFiles]);
    if (!selectedFileId && newFiles.length > 0) setSelectedFileId(newFiles[0].id);
  };

  const handleCleanCode = async (id: string) => {
    const file = files.find(f => f.id === id);
    if (!file) return;

    setFiles(prev => prev.map(f => f.id === id ? { ...f, status: 'analyzing' as const } : f));
    setIsProcessing(true);

    try {
      const report: MLReport = await analyzeCodeLocally(file.name, file.originalContent);

      let cleaned = file.originalContent;
      const findingsWithTokens: Finding[] = [];
      const newTokenMappings: TokenMapping[] = [...tokenRegistry];

      // Process findings and map to persistent tokens
      report.findings.forEach((f) => {
        let existingMapping = newTokenMappings.find(m => m.originalValue === f.originalText);

        if (!existingMapping) {
          // Create new unique numerical ID for this type
          const count = newTokenMappings.filter(m => m.type === f.type).length + 1;
          const token = `__REDACTED_${f.type}_${String(count).padStart(3, '0')}__`;

          existingMapping = {
            originalValue: f.originalText,
            token: token,
            type: f.type,
            firstSeen: Date.now()
          };
          newTokenMappings.push(existingMapping);
        }

        findingsWithTokens.push({
          ...f,
          suggestedReplacement: existingMapping.token
        });
      });

      setTokenRegistry(newTokenMappings);

      const sortedFindings = [...findingsWithTokens].sort((a, b) => b.lineNumber - a.lineNumber);
      const lines = cleaned.split('\n');

      sortedFindings.forEach(f => {
        const lineIdx = f.lineNumber - 1;
        if (lines[lineIdx]) {
          lines[lineIdx] = lines[lineIdx].split(f.originalText).join(f.suggestedReplacement);
        }
      });
      cleaned = lines.join('\n');

      const date = new Date();
      const mm = String(date.getMonth() + 1).padStart(2, '0');
      const dd = String(date.getDate()).padStart(2, '0');
      const yyyy = date.getFullYear();
      const formattedDate = `${mm}-${dd}-${yyyy}`;

      const lastDotIndex = file.name.lastIndexOf('.');
      const baseName = lastDotIndex !== -1 ? file.name.substring(0, lastDotIndex) : file.name;
      const extension = lastDotIndex !== -1 ? file.name.substring(lastDotIndex) : '';
      const newName = `${baseName}_cleaned_${formattedDate}${extension}`;

      const cleanedFile: CodeFile = {
        id: Math.random().toString(36).substr(2, 9),
        name: newName,
        path: `C:\\Projects\\Local\\Cleaned\\${newName}`,
        originalContent: file.originalContent,
        cleanedContent: cleaned,
        status: 'cleaned' as const,
        findings: findingsWithTokens,
        lastActionAt: Date.now(),
        folderId: 'cleaned'
      };

      setFiles(prev => [
        ...prev.map(f => f.id === id ? { ...f, status: 'pending' as const } : f),
        cleanedFile
      ]);
      setSelectedFileId(cleanedFile.id);
    } catch (error) {
      console.error(error);
      setFiles(prev => prev.map(f => f.id === id ? { ...f, status: 'error' as const } : f));
    } finally {
      setIsProcessing(false);
    }
  };

  const handleRestoreScript = (fileId: string, modifiedContent: string) => {
    const originalFile = files.find(f => f.id === fileId);
    if (!originalFile) return;

    let restored = modifiedContent;
    // Use the global token registry for restoration to ensure even if logic shifted, matches are found
    tokenRegistry.forEach(mapping => {
      restored = restored.split(mapping.token).join(mapping.originalValue);
    });

    const restoredFileId = Math.random().toString(36).substr(2, 9);
    const restoredFile: CodeFile = {
      id: restoredFileId,
      name: `Restored_${originalFile.name.replace(/_cleaned_\d{2}-\d{2}-\d{4}/, '')}`,
      path: `C:\\Projects\\Updated\\${originalFile.name}`,
      originalContent: originalFile.originalContent,
      updatedContent: modifiedContent,
      cleanedContent: restored,
      status: 'restored' as const,
      findings: [],
      folderId: 'updated'
    };

    setFiles(prev => [...prev, restoredFile]);
    setSelectedFileId(restoredFileId);
    setIsRestoreModalOpen(false);
  };

  const handleAddFolder = (parentId: string | null) => {
    const newFolder: Folder = {
      id: Math.random().toString(36).substr(2, 9),
      name: 'New Folder',
      parentId: parentId
    };
    setFolders([...folders, newFolder]);
  };

  const handleRenameFolder = (id: string, name: string) => {
    setFolders(folders.map(f => f.id === id ? { ...f, name } : f));
  };

  const handleDeleteFolder = (id: string) => {
    if (['input', 'cleaned', 'updated'].includes(id)) return; 
    setFolders(folders.filter(f => f.id !== id));
    setFiles(files.map(f => f.folderId === id ? { ...f, folderId: 'input' } : f));
  };

  const selectedFile = files.find(f => f.id === selectedFileId);

  return (
    <div className="flex h-screen bg-[#0f172a] text-slate-200 selection:bg-indigo-500/30 font-sans">
      <Sidebar 
        activeTab={activeTab} 
        setActiveTab={setActiveTab} 
        onOpenHelp={() => setIsHelpPortalOpen(true)}
        onOpenAbout={() => setIsAboutModalOpen(true)}
        onOpenVault={() => setIsVaultOpen(true)}
      />

      {activeTab === 'dashboard' && (
        <FolderAside 
          folders={folders} 
          files={files} 
          selectedFileId={selectedFileId} 
          onSelectFile={setSelectedFileId}
          onAddFolder={handleAddFolder}
          onDeleteFolder={handleDeleteFolder}
          onRenameFolder={handleRenameFolder}
          onFileUpload={handleFileUpload}
        />
      )}

      <main className="flex-1 flex flex-col min-w-0 bg-slate-950/20">
        <header className="h-14 border-b border-slate-800/60 flex items-center justify-between px-6 bg-slate-900/40 shrink-0 backdrop-blur-md">
          <div className="flex items-center gap-4">
            <span className="text-xs font-bold text-slate-400 flex items-center gap-2">
              <RefreshCw className={`w-3 h-3 ${isProcessing ? 'animate-spin text-indigo-400' : ''}`} />
              {isProcessing ? 'Sentinel Local-LLM Scrubbing...' : 'Sentinel Local-LLM Operational'}
            </span>
          </div>
          <div className="flex items-center gap-6">
             <div className="text-[10px] text-slate-500 font-mono flex items-center gap-2 bg-slate-800/30 px-3 py-1 rounded-full border border-slate-700">
               <ShieldAlert className="w-3 h-3 text-emerald-500" />
               SECURE ENCLAVE STATUS: ONLINE
             </div>
          </div>
        </header>

        {activeTab === 'dashboard' ? (
          <div className="flex-1 flex flex-col overflow-hidden">
            {/* Code Preview Box */}
            <div className="flex-1 p-6 flex flex-col min-h-0">
               <div className="bg-slate-900 border border-slate-800 rounded-xl overflow-hidden flex flex-col shadow-2xl flex-1">
                  <div className="bg-slate-800/50 px-4 py-2 border-b border-slate-800 flex justify-between items-center">
                    <div className="flex items-center gap-3">
                      <FileText className="w-4 h-4 text-indigo-400" />
                      <span className="text-xs font-semibold text-slate-300">
                        {selectedFile ? selectedFile.name : 'Sentinel Workspace'}
                      </span>
                    </div>
                    {selectedFile?.status === 'cleaned' && (
                      <span className="text-[10px] bg-emerald-500/10 text-emerald-400 px-2 py-0.5 rounded border border-emerald-500/20 font-bold animate-pulse">
                        SENSITIVE DATA REPLACED
                      </span>
                    )}
                  </div>
                  <div className="flex-1 bg-[#0d1117] p-6 code-font text-sm leading-relaxed overflow-auto whitespace-pre custom-scrollbar text-slate-300">
                    {selectedFile ? (
                      selectedFile.status === 'cleaned' || selectedFile.status === 'restored' 
                      ? (selectedFile.cleanedContent || selectedFile.originalContent)
                      : selectedFile.originalContent
                    ) : (
                      <div className="h-full flex flex-col items-center justify-center text-slate-600 gap-4">
                        <Layout className="w-16 h-16 opacity-5" />
                        <p className="text-sm italic">Import source files to begin local deep sanitization</p>
                      </div>
                    )}
                  </div>
               </div>
            </div>

            {/* Bottom Controls */}
            <div className="p-6 pt-0 border-t border-slate-800/40 bg-slate-900/20">
               <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                  {/* Action Group */}
                  <div className="flex flex-col gap-4">
                    <h3 className="text-[10px] font-bold text-slate-500 uppercase tracking-widest">Sentinel Controls</h3>
                    <div className="flex gap-3">
                      <button 
                        disabled={!selectedFile || isProcessing || selectedFile.status === 'cleaned' || selectedFile.status === 'restored'}
                        onClick={() => selectedFile && handleCleanCode(selectedFile.id)}
                        className="flex-1 flex items-center justify-center gap-2 bg-indigo-600 hover:bg-indigo-500 disabled:opacity-30 disabled:cursor-not-allowed text-white py-3 rounded-xl font-bold transition-all shadow-lg shadow-indigo-600/10"
                      >
                        <Zap className="w-4 h-4" />
                        Clean Code
                      </button>
                      <button 
                        onClick={() => setIsRestoreModalOpen(true)}
                        className="flex-1 flex items-center justify-center gap-2 bg-emerald-600 hover:bg-emerald-500 text-white py-3 rounded-xl font-bold transition-all shadow-lg shadow-emerald-600/10"
                      >
                        <RotateCcw className="w-4 h-4" />
                        Restore Script
                      </button>
                    </div>
                  </div>

                  {/* Smaller Drag Drop */}
                  <div className="flex flex-col gap-4">
                    <h3 className="text-[10px] font-bold text-slate-500 uppercase tracking-widest">Rapid Import</h3>
                    <label className="flex-1 border border-dashed border-slate-700 bg-slate-800/20 rounded-xl flex items-center justify-center gap-3 p-3 hover:bg-slate-800/40 cursor-pointer transition-all">
                      <Upload className="w-5 h-5 text-slate-500" />
                      <span className="text-xs text-slate-400">Drag source files for local-first scrubbing</span>
                      <input type="file" multiple className="hidden" onChange={(e) => handleFileUpload(e, 'input')} />
                    </label>
                  </div>
               </div>
            </div>
          </div>
        ) : (
          <div className="p-12 text-center text-slate-500 italic">
            Config and Audit sections are active. System developed by Bradley Hayes.
          </div>
        )}
      </main>

      <RestoreModal 
        isOpen={isRestoreModalOpen} 
        onClose={() => setIsRestoreModalOpen(false)}
        onRestore={handleRestoreScript}
        availableFiles={files.filter(f => f.status === 'cleaned')}
      />

      <AboutModal 
        isOpen={isAboutModalOpen}
        onClose={() => setIsAboutModalOpen(false)}
      />

      <HelpPortal 
        isOpen={isHelpPortalOpen}
        onClose={() => setIsHelpPortalOpen(false)}
      />

      <CodeVault 
        isOpen={isVaultOpen}
        onClose={() => setIsVaultOpen(false)}
        mappings={tokenRegistry}
