import { GoogleGenAI, Type } from "@google/genai";
import { MLReport, RiskType } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

/**
 * Sentinel Local-LLM acts as the SECOND-PASS VERIFIER and SENIOR ADVISOR.
 * It reviews the output of the deterministic C# engine.
 */
export const performAIReviewAndAdvice = async (filename: string, cleanedCode: string): Promise<string> => {
  const systemInstruction = `You are a Senior IT Advisor and QA Security Auditor.
Your task is to review code that has been processed by a deterministic redaction engine.

1. VERIFICATION: Look for any missed secrets, internal URLs, or credentials that the regex engine might have missed.
2. ADVICE: Provide senior-level architecture advice based on the code's logic.
3. FAIL CONDITION: If you see a clear credential or internal hostname, flag it explicitly.

Format your response as a professional report.`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Review the following REDACTED code. 
      Filename: ${filename}
      ---
      ${cleanedCode}`,
    config: {
      systemInstruction,
    }
  });

  return response.text || "No advice available at this time.";
};

import React, { useState } from 'react';
import Sidebar from './components/Sidebar';
import FolderAside from './components/FolderAside';
import RestoreModal from './components/RestoreModal';
import AboutModal from './components/AboutModal';
import HelpPortal from './components/HelpPortal';
import CodeVault from './components/CodeVault';
import { CodeFile, Finding, Folder, RiskType, TokenMapping } from './types';
import { performAIReviewAndAdvice } from './services/geminiService';
import { Layout, ShieldAlert, Zap, RotateCcw, RefreshCw, Upload, FileText, BrainCircuit } from 'lucide-react';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [files, setFiles] = useState<CodeFile[]>([]);
  const [folders, setFolders] = useState<Folder[]>([
    { id: 'input', name: 'input', parentId: null },
    { id: 'cleaned', name: 'cleaned', parentId: null },
    { id: 'updated', name: 'updated', parentId: null },
  ]);
  const [selectedFileId, setSelectedFileId] = useState<string | null>(null);
  const [isRestoreModalOpen, setIsRestoreModalOpen] = useState(false);
  const [isAboutModalOpen, setIsAboutModalOpen] = useState(false);
  const [isHelpPortalOpen, setIsHelpPortalOpen] = useState(false);
  const [isVaultOpen, setIsVaultOpen] = useState(false);
  const [isProcessing, setIsProcessing] = useState(false);
  const [advisorReport, setAdvisorReport] = useState<string | null>(null);

  const [tokenRegistry, setTokenRegistry] = useState<TokenMapping[]>([]);

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>, folderId: string = 'input') => {
    if (!e.target.files) return;
    const filesArray = Array.from(e.target.files) as File[];

    const newFiles: CodeFile[] = filesArray.map(file => ({
      id: Math.random().toString(36).substr(2, 9),
      name: file.name,
      path: `C:\\Projects\\Local\\${file.name}`,
      originalContent: '',
      status: 'pending' as const,
      findings: [],
      folderId: folderId
    }));

    newFiles.forEach(nf => {
      const reader = new FileReader();
      const actualFile = filesArray.find(f => f.name === nf.name);
      if (actualFile) {
        reader.onload = (event) => {
          setFiles(prev => prev.map(p => p.id === nf.id ? { ...p, originalContent: event.target?.result as string } : p));
        };
        reader.readAsText(actualFile);
      }
    });

    setFiles(prev => [...prev, ...newFiles]);
    if (!selectedFileId && newFiles.length > 0) setSelectedFileId(newFiles[0].id);
  };

  /**
   * DETERMINISTIC SCANNER (SIMULATING C# LOGIC)
   * Uses Regex only. No AI.
   */
  const handleCleanCode = async (id: string) => {
    const file = files.find(f => f.id === id);
    if (!file) return;

    setFiles(prev => prev.map(f => f.id === id ? { ...f, status: 'analyzing' as const } : f));
    setIsProcessing(true);

    try {
      let cleaned = file.originalContent;
      const newTokenMappings: TokenMapping[] = [...tokenRegistry];

      // REGEX PATTERNS (Deterministic Engine)
      const patterns = [
        { type: RiskType.PRIVATE_URL, regex: /(https?:\/\/[^\s"'<>]+)|(\b[a-z0-9.-]+\.local\b)|(\binternal\b|\bintranet\b|\bgateway\b)/gi },
        { type: RiskType.API_SECRET, regex: /(\b(password|secret|token|key|jwt|oauth|auth)\b\s*[:=]\s*["']([^"']+)["'])|([a-zA-Z0-9]{16,})/gi },
        { type: RiskType.CREDENTIAL, regex: /(\buser(name)?\b\s*[:=]\s*["']([^"']+)["'])/gi },
        { type: RiskType.COMPANY_NAME, regex: /(\bcompany\b|\bcorp\b|\benterprise\b)/gi }
      ];

      patterns.forEach(p => {
        cleaned = cleaned.replace(p.regex, (match) => {
          // Simplified extraction of value vs variable name for the token mapping
          const valueToRedact = match.includes(':') || match.includes('=') ? match.split(/[=:]/)[1].replace(/["']/g, '').trim() : match;

          let existing = newTokenMappings.find(m => m.originalValue === valueToRedact);
          if (!existing) {
            const count = newTokenMappings.filter(m => m.type === p.type).length + 1;
            const token = `__REDACTED_${p.type}_${String(count).padStart(3, '0')}__`;
            existing = { originalValue: valueToRedact, token, type: p.type, firstSeen: Date.now() };
            newTokenMappings.push(existing);
          }
          return match.replace(valueToRedact, existing.token);
        });
      });

      setTokenRegistry(newTokenMappings);

      // AI SECOND-PASS & ADVISOR
      const advice = await performAIReviewAndAdvice(file.name, cleaned);
      setAdvisorReport(advice);
      setIsHelpPortalOpen(true); // Open "Second Window" Advisor

      const date = new Date();
      const formattedDate = `${String(date.getMonth() + 1).padStart(2, '0')}-${String(date.getDate()).padStart(2, '0')}-${date.getFullYear()}`;
      const newName = `${file.name.split('.')[0]}_cleaned_${formattedDate}.${file.name.split('.')[1]}`;

      const cleanedFile: CodeFile = {
        id: Math.random().toString(36).substr(2, 9),
        name: newName,
        path: `C:\\Projects\\Local\\Cleaned\\${newName}`,
        originalContent: file.originalContent,
        cleanedContent: cleaned,
        status: 'cleaned' as const,
        findings: [], // Findings now tracked by Token Registry
        lastActionAt: Date.now(),
        folderId: 'cleaned'
      };

      setFiles(prev => [
        ...prev.map(f => f.id === id ? { ...f, status: 'pending' as const } : f),
        cleanedFile
      ]);
      setSelectedFileId(cleanedFile.id);
    } catch (error) {
      console.error(error);
      setFiles(prev => prev.map(f => f.id === id ? { ...f, status: 'error' as const } : f));
    } finally {
      setIsProcessing(false);
    }
  };

  const handleRestoreScript = (fileId: string, modifiedContent: string) => {
    const originalFile = files.find(f => f.id === fileId);
    if (!originalFile) return;
    let restored = modifiedContent;
    tokenRegistry.forEach(mapping => {
      restored = restored.split(mapping.token).join(mapping.originalValue);
    });
    const restoredFileId = Math.random().toString(36).substr(2, 9);
    setFiles(prev => [...prev, {
      id: restoredFileId,
      name: `Restored_${originalFile.name}`,
      path: `C:\\Projects\\Updated\\${originalFile.name}`,
      originalContent: originalFile.originalContent,
      cleanedContent: restored,
      status: 'restored' as const,
      findings: [],
      folderId: 'updated'
    }]);
    setSelectedFileId(restoredFileId);
    setIsRestoreModalOpen(false);
  };

  const selectedFile = files.find(f => f.id === selectedFileId);

  return (
    <div className="flex h-screen bg-[#0f172a] text-slate-200 selection:bg-indigo-500/30 font-sans">
      <Sidebar 
        activeTab={activeTab} 
        setActiveTab={setActiveTab} 
        onOpenHelp={() => setIsHelpPortalOpen(true)}
        onOpenAbout={() => setIsAboutModalOpen(true)}
        onOpenVault={() => setIsVaultOpen(true)}
      />

      {activeTab === 'dashboard' && (
        <FolderAside 
          folders={folders} 
          files={files} 
          selectedFileId={selectedFileId} 
          onSelectFile={setSelectedFileId}
          onAddFolder={() => {}} 
          onDeleteFolder={() => {}} 
          onRenameFolder={() => {}} 
          onFileUpload={handleFileUpload}
        />
      )}

      <main className="flex-1 flex flex-col min-w-0 bg-slate-950/20">
        <header className="h-14 border-b border-slate-800/60 flex items-center justify-between px-6 bg-slate-900/40 shrink-0 backdrop-blur-md">
          <div className="flex items-center gap-4">
            <span className="text-xs font-bold text-slate-400 flex items-center gap-2">
              <RefreshCw className={`w-3 h-3 ${isProcessing ? 'animate-spin text-indigo-400' : ''}`} />
              {isProcessing ? 'Deterministic Engine Scrubbing...' : 'Deterministic Engine Ready'}
            </span>
          </div>
