import React, { useState } from 'react';
import Sidebar from './components/Sidebar';
import FolderAside from './components/FolderAside';
import RestoreModal from './components/RestoreModal';
import AboutModal from './components/AboutModal';
import HelpPortal from './components/HelpPortal';
import CodeVault from './components/CodeVault';
import { CodeFile, Finding, Folder, RiskType, TokenMapping } from './types';
import { performAIReviewAndAdvice } from './services/geminiService';
import { Layout, ShieldAlert, Zap, RotateCcw, RefreshCw, Upload, FileText, BrainCircuit } from 'lucide-react';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [files, setFiles] = useState<CodeFile[]>([]);
  const [folders, setFolders] = useState<Folder[]>([
    { id: 'input', name: 'input', parentId: null },
    { id: 'cleaned', name: 'cleaned', parentId: null },
    { id: 'updated', name: 'updated', parentId: null },
  ]);
  const [selectedFileId, setSelectedFileId] = useState<string | null>(null);
  const [isRestoreModalOpen, setIsRestoreModalOpen] = useState(false);
  const [isAboutModalOpen, setIsAboutModalOpen] = useState(false);
  const [isHelpPortalOpen, setIsHelpPortalOpen] = useState(false);
  const [isVaultOpen, setIsVaultOpen] = useState(false);
  const [isProcessing, setIsProcessing] = useState(false);
  const [advisorReport, setAdvisorReport] = useState<string | null>(null);

  const [tokenRegistry, setTokenRegistry] = useState<TokenMapping[]>([]);

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>, folderId: string = 'input') => {
    if (!e.target.files) return;
    const filesArray = Array.from(e.target.files) as File[];

    const newFiles: CodeFile[] = filesArray.map(file => ({
      id: Math.random().toString(36).substr(2, 9),
      name: file.name,
      path: `C:\\Projects\\Local\\${file.name}`,
      originalContent: '',
      status: 'pending' as const,
      findings: [],
      folderId: folderId
    }));

    newFiles.forEach(nf => {
      const reader = new FileReader();
      const actualFile = filesArray.find(f => f.name === nf.name);
      if (actualFile) {
        reader.onload = (event) => {
          setFiles(prev => prev.map(p => p.id === nf.id ? { ...p, originalContent: event.target?.result as string } : p));
        };
        reader.readAsText(actualFile);
      }
    });

    setFiles(prev => [...prev, ...newFiles]);
    if (!selectedFileId && newFiles.length > 0) setSelectedFileId(newFiles[0].id);
  };

  const handleCodeChange = (newContent: string) => {
    if (!selectedFileId) return;
    setFiles(prev => prev.map(f => {
      if (f.id === selectedFileId) {
        if (f.status === 'cleaned' || f.status === 'restored') {
          return { ...f, cleanedContent: newContent };
        }
        return { ...f, originalContent: newContent };
      }
      return f;
    }));
  };

  /**
   * ENHANCED DETERMINISTIC SCANNER
   * Strictly Regex-based logic for identifying secrets and identifiers.
   */
  const handleCleanCode = async (id: string) => {
    const file = files.find(f => f.id === id);
    if (!file) return;

    setFiles(prev => prev.map(f => f.id === id ? { ...f, status: 'analyzing' as const } : f));
    setIsProcessing(true);

    try {
      const contentToClean = file.originalContent;
      let cleaned = contentToClean;
      const newTokenMappings: TokenMapping[] = [...tokenRegistry];

      // REGEX PATTERNS (Stronger Deterministic Engine)
      const patterns = [
        // 1. URLs & Internal Hosts
        { type: RiskType.PRIVATE_URL, regex: /(https?:\/\/[^\s"'<>]+)|(\b[a-z0-9.-]+\.local\b)|(\binternal\b|\bintranet\b|\bgateway\b)/gi },

        // 2. Sensitive Identifiers (Assignment based)
        // Catches: password, secret, key, token, jwt, oauth, auth, api, client, db, internal, private
        { type: RiskType.API_SECRET, regex: /(\b(password|secret|key|token|jwt|oauth|auth|api|client|db|internal|private)[a-z0-9_-]*\s*[:=]\s*["']([^"']+)["'])/gi },

        // 3. Company Specific Names (e.g., Brad Onsite Medical)
        { type: RiskType.COMPANY_NAME, regex: /(\bBrad Onsite Medical\b|\bBOM\b|\bCompany\sName\b|\bProprietary\b)/gi },

        // 4. Standalone Long Literals (>= 16 chars)
        { type: RiskType.API_SECRET, regex: /["']([a-zA-Z0-9!@#$%^&*()_\-+=]{16,})["']/g }
      ];

      patterns.forEach(p => {
        cleaned = cleaned.replace(p.regex, (match, p1, p2, p3) => {
          // If we matched an assignment (3 groups), p3 is the value. 
          // If we matched a simple string (1 group), match or p1 is the value.
          let valueToRedact = match;

          if (p3) {
            valueToRedact = p3; // Value from assignment like $var = "value"
          } else if (p1 && match.startsWith('"') || match.startsWith("'")) {
            valueToRedact = p1; // Value from quoted string like "long-literal"
          }

          let existing = newTokenMappings.find(m => m.originalValue === valueToRedact);
          if (!existing) {
            const count = newTokenMappings.filter(m => m.type === p.type).length + 1;
            const token = `__REDACTED_${p.type}_${String(count).padStart(3, '0')}__`;
            existing = { originalValue: valueToRedact, token, type: p.type, firstSeen: Date.now() };
            newTokenMappings.push(existing);
          }

          // Only replace the actual value within the match to preserve syntax
          return match.replace(valueToRedact, existing.token);
        });
      });

      setTokenRegistry(newTokenMappings);

      // AI SECOND-PASS & SENIOR ADVISOR
      const advice = await performAIReviewAndAdvice(file.name, cleaned);
      setAdvisorReport(advice);
      setIsHelpPortalOpen(true);

      const date = new Date();
      const formattedDate = `${String(date.getMonth() + 1).padStart(2, '0')}-${String(date.getDate()).padStart(2, '0')}-${date.getFullYear()}`;
      const newName = `${file.name.split('.')[0]}_cleaned_${formattedDate}.${file.name.split('.')[1] || 'txt'}`;

      const cleanedFile: CodeFile = {
        id: Math.random().toString(36).substr(2, 9),
        name: newName,
        path: `C:\\Projects\\Local\\Cleaned\\${newName}`,
        originalContent: file.originalContent,
        cleanedContent: cleaned,
        status: 'cleaned' as const,
        findings: [],
        lastActionAt: Date.now(),
        folderId: 'cleaned'
      };

      setFiles(prev => [
        ...prev.map(f => f.id === id ? { ...f, status: 'pending' as const } : f),
        cleanedFile
      ]);
      setSelectedFileId(cleanedFile.id);
    } catch (error) {
      console.error(error);
      setFiles(prev => prev.map(f => f.id === id ? { ...f, status: 'error' as const } : f));
    } finally {
      setIsProcessing(false);
    }
  };

  const handleRestoreScript = (fileId: string, modifiedContent: string) => {
    const originalFile = files.find(f => f.id === fileId);
    if (!originalFile) return;
    let restored = modifiedContent;
    tokenRegistry.forEach(mapping => {
      restored = restored.split(mapping.token).join(mapping.originalValue);
    });
    const restoredFileId = Math.random().toString(36).substr(2, 9);
    setFiles(prev => [...prev, {
      id: restoredFileId,
      name: `Restored_${originalFile.name}`,
      path: `C:\\Projects\\Updated\\${originalFile.name}`,
      originalContent: originalFile.originalContent,
      cleanedContent: restored,
      status: 'restored' as const,
      findings: [],
      folderId: 'updated'
    }]);
    setSelectedFileId(restoredFileId);
    setIsRestoreModalOpen(false);
  };

  const selectedFile = files.find(f => f.id === selectedFileId);
  const currentDisplayContent = selectedFile 
    ? (selectedFile.status === 'cleaned' || selectedFile.status === 'restored' 
        ? selectedFile.cleanedContent 
        : selectedFile.originalContent) 
    : '';

  return (
    <div className="flex h-screen bg-[#0f172a] text-slate-200 selection:bg-indigo-500/30 font-sans overflow-hidden">
      <Sidebar 
        activeTab={activeTab} 
        setActiveTab={setActiveTab} 
        onOpenHelp={() => setIsHelpPortalOpen(true)}
        onOpenAbout={() => setIsAboutModalOpen(true)}
        onOpenVault={() => setIsVaultOpen(true)}
      />

      {activeTab === 'dashboard' && (
        <FolderAside 
          folders={folders} 
          files={files} 
          selectedFileId={selectedFileId} 
          onSelectFile={setSelectedFileId}
          onAddFolder={() => {}} 
          onDeleteFolder={() => {}} 
          onRenameFolder={() => {}} 
          onFileUpload={handleFileUpload}
        />
      )}

      <main className="flex-1 flex flex-col min-w-0 bg-slate-950/20">
        <header className="h-14 border-b border-slate-800/60 flex items-center justify-between px-6 bg-slate-900/40 shrink-0 backdrop-blur-md">
          <div className="flex items-center gap-4">
            <span className="text-xs font-bold text-slate-400 flex items-center gap-2">
              <RefreshCw className={`w-3 h-3 ${isProcessing ? 'animate-spin text-indigo-400' : ''}`} />
              {isProcessing ? 'Deterministic Engine Scrubbing...' : 'Deterministic Engine Ready'}
            </span>
          </div>
          <div className="flex items-center gap-6">
             <div className="text-[10px] text-slate-500 font-mono flex items-center gap-2 bg-slate-800/30 px-3 py-1 rounded-full border border-slate-700">
               <BrainCircuit className="w-3 h-3 text-indigo-500" />
               AI ADVISOR: {advisorReport ? 'REPORT READY' : 'STANDBY'}
             </div>
          </div>
        </header>

        <div className="flex-1 flex flex-col overflow-hidden">
          <div className="flex-1 p-6 flex flex-col min-h-0">
             <div className="bg-slate-900 border border-slate-800 rounded-xl overflow-hidden flex flex-col shadow-2xl flex-1">
                <div className="bg-slate-800/50 px-4 py-2 border-b border-slate-800 flex justify-between items-center">
                  <div className="flex items-center gap-3">
                    <FileText className="w-4 h-4 text-indigo-400" />
                    <span className="text-xs font-semibold text-slate-300">
                      {selectedFile ? selectedFile.name : 'Deterministic Workspace'}
                    </span>
                  </div>
                  {selectedFile?.status === 'cleaned' && (
                    <span className="text-[10px] bg-emerald-500/10 text-emerald-400 px-2 py-0.5 rounded border border-emerald-500/20 font-bold">
                      DETERMINISTIC REDACTION COMPLETE
                    </span>
                  )}
                </div>
                <div className="flex-1 relative bg-[#0d1117]">
                  {selectedFile ? (
                    <textarea
                      spellCheck={false}
                      className="w-full h-full p-6 bg-transparent code-font text-sm leading-relaxed text-slate-300 outline-none resize-none custom-scrollbar"
                      value={currentDisplayContent}
                      onChange={(e) => handleCodeChange(e.target.value)}
                    />
                  ) : (
                    <div className="h-full flex flex-col items-center justify-center text-slate-600 gap-4 text-center max-w-sm mx-auto">
                      <Layout className="w-16 h-16 opacity-5" />
                      <p className="text-sm">Import source files to begin local deterministic sanitization using the C# Engine logic.</p>
                    </div>
                  )}
                </div>
             </div>
          </div>

          <div className="p-6 pt-0 border-t border-slate-800/40 bg-slate-900/20 shrink-0">
             <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div className="flex flex-col gap-4">
                  <h3 className="text-[10px] font-bold text-slate-500 uppercase tracking-widest">Scanner Controls</h3>
                  <div className="flex gap-3">
                    <button 
                      disabled={!selectedFile || isProcessing || selectedFile.status === 'cleaned' || selectedFile.status === 'restored'}
                      onClick={() => selectedFile && handleCleanCode(selectedFile.id)}
                      className="flex-1 flex items-center justify-center gap-2 bg-indigo-600 hover:bg-indigo-500 disabled:opacity-30 disabled:cursor-not-allowed text-white py-3 rounded-xl font-bold transition-all shadow-lg"
                    >
                      <Zap className="w-4 h-4" />
                      Deterministic Clean
                    </button>
                    <button 
                      onClick={() => setIsRestoreModalOpen(true)}
                      className="flex-1 flex items-center justify-center gap-2 bg-emerald-600 hover:bg-emerald-500 text-white py-3 rounded-xl font-bold transition-all shadow-lg"
                    >
                      <RotateCcw className="w-4 h-4" />
                      Restore Code
                    </button>
                  </div>
                </div>
                <div className="flex flex-col gap-4">
                  <h3 className="text-[10px] font-bold text-slate-500 uppercase tracking-widest">Import Data</h3>
                  <label className="flex-1 border border-dashed border-slate-700 bg-slate-800/20 rounded-xl flex items-center justify-center gap-3 p-3 hover:bg-slate-800/40 cursor-pointer transition-all">
                    <Upload className="w-5 h-5 text-slate-500" />
                    <span className="text-xs text-slate-400">Drag files for local-only scrubbing</span>
                    <input type="file" multiple className="hidden" onChange={(e) => handleFileUpload(e, 'input')} />
                  </label>
                </div>
             </div>
          </div>
        </div>
      </main>

      <RestoreModal isOpen={isRestoreModalOpen} onClose={() => setIsRestoreModalOpen(false)} onRestore={handleRestoreScript} availableFiles={files.filter(f => f.status === 'cleaned')} />
